 {id:"de_a2_g_perfekt",title:"Perfektum (minulý čas)",type:"grammar",theory:"Perfektum je nejčastější minulý čas v mluvené němčině. Tvoří se pomocným slovesem <b>haben</b> nebo <b>sein</b> + příčestí minulé (ge-...-t/-en): Ich habe gespielt. Ich bin gegangen. <b>Sein</b> se používá u sloves pohybu a změny stavu.",table:[["Sloveso","Pomocné","Příčestí"],["spielen","haben","gespielt"],["gehen","sein","gegangen"],["essen","haben","gegessen"],["fahren","sein","gefahren"]],items:[["Ich ___ gestern Fußball gespielt.","habe",["habe","bin","hat"],"Včera jsem hrál fotbal."],["Wir ___ nach Hause gegangen.","sind",["sind","haben","ist"],"Šli jsme domů."],["Er ___ eine Pizza gegessen.","hat",["hat","ist","habe"],"Snědl pizzu."],["Sie ___ mit dem Zug gefahren.","ist",["ist","hat","sind"],"Jela vlakem."],["___ du den Film gesehen?","Hast",["Hast","Bist","Habt"],"Viděl jsi ten film?"],["Ich ___ heute früh aufgestanden.","bin",["bin","habe","ist"],"Dnes jsem vstal brzy."],["Wir ___ Deutsch gelernt.","haben",["haben","sind","hat"],"Učili jsme se německy."],["Sie ___ lange geschlafen.","hat",["hat","ist","haben"],"Dlouho spala."]]},
 {id:"de_a2_g_praeteritum",title:"Préteritum sein/haben",type:"grammar",theory:"U sloves <b>sein</b> a <b>haben</b> se v minulosti používá préteritum místo perfekta: ich war (byl jsem), ich hatte (měl jsem). Časování: war/warst/war/waren/wart/waren; hatte/hattest/hatte/hatten/hattet/hatten.",table:[["Osoba","sein (préteritum)","haben (préteritum)"],["ich","war","hatte"],["du","warst","hattest"],["er/sie/es","war","hatte"],["wir","waren","hatten"],["ihr","wart","hattet"],["sie/Sie","waren","hatten"]],items:[["Ich ___ gestern krank.","war",["war","hatte","warst"],"Včera jsem byl nemocný."],["Wir ___ keine Zeit.","hatten",["hatten","waren","hatte"],"Neměli jsme čas."],["___ du schon einmal in Berlin?","Warst",["Warst","Hattest","War"],"Byl jsi už někdy v Berlíně?"],["Er ___ als Kind einen Hund.","hatte",["hatte","war","hatten"],"Jako dítě měl psa."],["Das Wetter ___ sehr schön.","war",["war","hatte","waren"],"Počasí bylo velmi hezké."],["Ihr ___ gestern viel Glück.","hattet",["hattet","wart","hattest"],"Včera jste měli velké štěstí."],["Sie ___ müde nach der Arbeit.","waren",["waren","hatten","war"],"Po práci byli unavení."],["Ich ___ früher lange Haare.","hatte",["hatte","war","hattest"],"Dřív jsem měl dlouhé vlasy."]]},
 {id:"de_a2_g_dativ",title:"3. pád (Dativ)",type:"grammar",theory:"Třetí pád (Dativ) se používá u nepřímého předmětu (komu? čemu?). Členy: der → dem, die → der, das → dem, množné číslo → den (+n u podstatného jména): Ich gebe dem Mann das Buch.",table:[["1. pád","3. pád (Dativ)"],["der Mann","dem Mann"],["die Frau","der Frau"],["das Kind","dem Kind"],["die Kinder","den Kindern"]],items:[["Ich gebe ___ Mann das Buch.","dem",["dem","den","der"],"Dávám tomu muži knihu."],["Sie hilft ___ Frau.","der",["der","dem","die"],"Pomáhá té ženě."],["Das Auto gehört ___ Lehrer.","dem",["dem","den","der"],"To auto patří učiteli."],["Er dankt ___ Eltern.","den",["den","dem","der"],"Děkuje rodičům."],["Wir schenken ___ Kind ein Spielzeug.","dem",["dem","den","das"],"Darujeme dítěti hračku."],["Der Kuchen schmeckt ___ Gästen.","den",["den","dem","der"],"Koláč chutná hostům."],["Ich zeige ___ Freundin die Stadt.","der",["der","dem","die"],"Ukazuji kamarádce město."],["Das Buch gehört ___ Schülerin.","der",["der","dem","das"],"Ta kniha patří žákyni."]]},
 {id:"de_a2_g_wechselpraep",title:"Předložky se 3. a 4. pádem",type:"grammar",theory:"Předložky in, an, auf, über, unter, vor, hinter, neben, zwischen se pojí se 4. pádem při pohybu (kam?) a se 3. pádem při poloze (kde?): Ich gehe in die Schule (kam?) × Ich bin in der Schule (kde?).",table:[["Otázka","Pád","Příklad"],["Wohin? (kam?)","4. pád","in die Schule"],["Wo? (kde?)","3. pád","in der Schule"]],items:[["Ich gehe in ___ Schule.","die",["die","der","dem"],"Jdu do školy."],["Ich bin in ___ Schule.","der",["der","die","den"],"Jsem ve škole."],["Die Katze springt auf ___ Tisch.","den",["den","dem","der"],"Kočka skáče na stůl."],["Die Katze sitzt auf ___ Tisch.","dem",["dem","den","die"],"Kočka sedí na stole."],["Er hängt das Bild an ___ Wand.","die",["die","der","dem"],"Věší obraz na zeď."],["Das Bild hängt an ___ Wand.","der",["der","die","dem"],"Obraz visí na zdi."],["Wir fahren in ___ Stadt.","die",["die","der","dem"],"Jedeme do města."],["Das Auto steht vor ___ Haus.","dem",["dem","das","der"],"Auto stojí před domem."]]},
 {id:"de_a2_g_komparativ",title:"Stupňování přídavných jmen",type:"grammar",theory:"Druhý stupeň se tvoří koncovkou <b>-er</b>, třetí stupeň pomocí <b>am -sten</b>: klein → kleiner → am kleinsten. Krátká slova často přehlasují: alt → älter, groß → größer. Nepravidelně: gut → besser → am besten, viel → mehr → am meisten. Srovnání: größer <b>als</b>…",table:[["1. stupeň","2. stupeň","3. stupeň"],["klein","kleiner","am kleinsten"],["alt","älter","am ältesten"],["gut","besser","am besten"],["viel","mehr","am meisten"]],items:[["Mein Bruder ist ___ als ich.","älter",["älter","alter","am ältesten"],"Můj bratr je starší než já."],["Dieses Auto ist ___ als das andere.","besser",["besser","guter","am besten"],"Tohle auto je lepší než to druhé."],["Der Mount Everest ist ___ Berg der Welt.","der höchste",["der höchste","höher","hoch"],"Mount Everest je nejvyšší hora světa."],["Im Sommer sind die Tage ___ .","länger",["länger","lang","am längsten"],"V létě jsou dny delší."],["Sie spricht Deutsch ___ als ich.","besser",["besser","gut","am besten"],"Mluví německy lépe než já."],["Das ist das ___ Buch von allen.","beste",["beste","besser","gute"],"To je nejlepší kniha ze všech."],["Heute ist es ___ als gestern.","kälter",["kälter","kalt","am kältesten"],"Dnes je chladněji než včera."],["Er hat ___ Geld als sein Bruder.","mehr",["mehr","viel","am meisten"],"Má víc peněz než jeho bratr."]]},
 {id:"de_a2_g_futur",title:"Budoucí čas (werden)",type:"grammar",theory:"Budoucnost se vyjadřuje slovesem <b>werden</b> + infinitiv na konci věty: Ich werde morgen kommen. Časování werden: werde, wirst, wird, werden, werdet, werden. Často se budoucnost vyjadřuje i přítomným časem s časovým údajem.",table:[["Osoba","werden"],["ich","werde"],["du","wirst"],["er/sie/es","wird"],["wir","werden"],["ihr","werdet"],["sie/Sie","werden"]],items:[["Ich ___ dich morgen anrufen.","werde",["werde","wirst","wird"],"Zítra ti zavolám."],["Es ___ morgen regnen.","wird",["wird","werde","werden"],"Zítra bude pršet."],["Wir ___ nächstes Jahr nach Spanien fahren.","werden",["werden","wird","werdet"],"Příští rok pojedeme do Španělska."],["___ du mir helfen?","Wirst",["Wirst","Wird","Werdet"],"Pomůžeš mi?"],["Sie ___ bald ein Haus kaufen.","werden",["werden","wird","werde"],"Brzy koupí dům."],["Er ___ Arzt werden.","wird",["wird","werde","wirst"],"Stane se lékařem."],["Ihr ___ die Prüfung bestehen.","werdet",["werdet","werden","wirst"],"Zkoušku složíte."],["Ich ___ mehr Sport machen.","werde",["werde","wird","werden"],"Budu víc sportovat."]]},
 {id:"de_a2_g_nebensatz",title:"Vedlejší věty (weil, dass)",type:"grammar",theory:"Ve vedlejších větách po spojkách <b>weil</b> (protože) a <b>dass</b> (že) jde časované sloveso na konec věty: Ich bleibe zu Hause, weil ich krank <b>bin</b>. Ich glaube, dass er morgen <b>kommt</b>.",table:[["Spojka","Význam","Příklad"],["weil","protože","..., weil ich krank bin."],["dass","že","..., dass er kommt."]],items:[["Ich bleibe zu Hause, weil ich krank ___ .","bin",["bin","ist","bist"],"Zůstávám doma, protože jsem nemocný."],["Er sagt, dass er morgen ___ .","kommt",["kommt","kommen","komme"],"Říká, že zítra přijde."],["Wir lernen Deutsch, weil wir in Berlin ___ .","wohnen",["wohnen","wohnt","wohne"],"Učíme se německy, protože bydlíme v Berlíně."],["Ich glaube, dass das Wetter schön ___ .","wird",["wird","werden","wirst"],"Myslím, že počasí bude hezké."],["Sie ist müde, weil sie wenig geschlafen ___ .","hat",["hat","ist","haben"],"Je unavená, protože málo spala."],["Ich hoffe, dass du Zeit ___ .","hast",["hast","hat","habt"],"Doufám, že máš čas."],["Er kommt nicht, weil er arbeiten ___ .","muss",["muss","musst","müssen"],"Nepřijde, protože musí pracovat."],["Wir wissen, dass Deutsch schwer ___ .","ist",["ist","bin","sind"],"Víme, že němčina je těžká."]]},
 {id:"de_a2_g_imperativ",title:"Rozkazovací způsob",type:"grammar",theory:"Rozkazovací způsob má tři tvary: <b>du</b> → Komm! (bez -st a bez zájmena), <b>ihr</b> → Kommt!, <b>Sie</b> → Kommen Sie! U sloves s přehláskou v du-tvaru přehláska mizí: fahren → Fahr!",table:[["Osoba","spielen","kommen"],["du","Spiel!","Komm!"],["ihr","Spielt!","Kommt!"],["Sie","Spielen Sie!","Kommen Sie!"]],items:[["___ bitte langsamer! (du)","Sprich",["Sprich","Sprichst","Sprechen"],"Mluv prosím pomaleji!"],["___ Sie bitte Platz!","Nehmen",["Nehmen","Nimm","Nehmt"],"Posaďte se prosím!"],["___ die Tür zu! (du)","Mach",["Mach","Machst","Machen"],"Zavři dveře!"],["___ eure Hausaufgaben! (ihr)","Macht",["Macht","Mach","Machen"],"Udělejte si domácí úkoly!"],["___ mir bitte! (du)","Hilf",["Hilf","Hilfst","Helfen"],"Pomoz mi prosím!"],["___ Sie mich bitte an!","Rufen",["Rufen","Ruf","Ruft"],"Zavolejte mi prosím!"],["___ vorsichtig! (ihr)","Seid",["Seid","Sei","Sind"],"Buďte opatrní!"],["___ keine Angst! (du)","Hab",["Hab","Habt","Haben"],"Neboj se!"]]},
 {id:"de_a2_g_trennbar",title:"Odlučitelné předpony",type:"grammar",theory:"Slovesa s odlučitelnou předponou (auf-, an-, ein-, mit-, ab-...) se v přítomném čase rozdělují — předpona jde na konec věty: aufstehen → Ich stehe um 7 Uhr <b>auf</b>. V perfektu: Ich bin aufgestanden (ge- se vkládá mezi předponu a kmen).",table:[["Infinitiv","Věta"],["aufstehen","Ich stehe früh auf."],["anrufen","Ich rufe dich an."],["einkaufen","Wir kaufen im Supermarkt ein."],["mitkommen","Kommst du mit?"]],items:[["Ich stehe jeden Tag um 6 Uhr ___ .","auf",["auf","an","ein"],"Každý den vstávám v 6 hodin."],["Er ruft seine Mutter ___ .","an",["an","auf","mit"],"Volá své matce."],["Wir kaufen am Samstag ___ .","ein",["ein","auf","an"],"V sobotu nakupujeme."],["Kommst du heute Abend ___ ?","mit",["mit","an","auf"],"Přijdeš dnes večer s námi?"],["Der Zug fährt um 8 Uhr ___ .","ab",["ab","auf","an"],"Vlak odjíždí v 8 hodin."],["Sie macht das Fenster ___ .","auf",["auf","ab","ein"],"Otevírá okno."],["Ich lade dich zur Party ___ .","ein",["ein","auf","mit"],"Zvu tě na párty."],["Bitte machen Sie die Tür ___ .","zu",["zu","ab","an"],"Zavřete prosím dveře."]]}
