 {id:"de_c2_g_modalpartikeln",title:"Modální částice (doch, ja, eben)",type:'grammar',theory:"Modální částice dodávají větě postoj mluvčího: <b>doch</b> (přece), <b>ja</b> (přece/vždyť), <b>eben/halt</b> (prostě), <b>mal</b> (zjemnění), <b>schon</b> (uklidnění). Das ist <b>doch</b> klar! Komm <b>mal</b> her!",table:[["Částice","Funkce","Příklad"],["doch","přece (rozpor)","Das weißt du doch!"],["ja","vždyť (známý fakt)","Es ist ja kalt."],["eben/halt","prostě (rezignace)","So ist es eben."],["mal","zjemnění výzvy","Komm mal her!"]],items:[["Das habe ich dir ___ gesagt!","doch",["doch","mal","eben"],"To jsem ti přece říkal!"],["Komm ___ her, ich zeige dir etwas.","mal",["mal","doch nur","ja"],"Pojď sem, něco ti ukážu."],["Es ist ___ kalt draußen — kein Wunder.","ja",["ja","mal","erst"],"Vždyť je venku zima — žádný div."],["So ist das Leben ___ .","eben",["eben","mal","ja doch"],"Takový je prostě život."],["Das wird ___ wieder gut.","schon",["schon","eben","mal"],"To zase bude dobré."],["Sei ___ nicht so streng mit dir!","doch",["doch","ja","eben"],"Nebuď na sebe přece tak přísný!"],["Er ist ___ noch ein Kind.","halt",["halt","mal","schon doch"],"Je to prostě ještě dítě."],["Warte ___ einen Moment!","mal",["mal","eben ja","doch schon"],"Počkej chvilku!"]]},
 {id:"de_c2_g_kollokationen",title:"Pokročilé kolokace",type:'grammar',theory:"Rodilí mluvčí používají ustálená spojení: eine Rede <b>halten</b> (ne 'machen'), ein Risiko <b>eingehen</b>, Abschied <b>nehmen</b>, eine Niederlage <b>erleiden</b>, großen Wert auf etwas <b>legen</b>.",table:[["Kolokace","Význam"],["eine Rede halten","pronést projev"],["ein Risiko eingehen","podstoupit riziko"],["eine Niederlage erleiden","utrpět porážku"],["Wert legen auf","klást důraz na"]],items:[["Der Präsident ___ eine lange Rede.","hielt",["hielt","machte","gab"],"Prezident pronesl dlouhý projev."],["Sie wollte kein Risiko ___ .","eingehen",["eingehen","machen","nehmen"],"Nechtěla podstoupit žádné riziko."],["Die Mannschaft ___ eine bittere Niederlage.","erlitt",["erlitt","machte","bekam"],"Tým utrpěl hořkou porážku."],["Wir ___ großen Wert auf Qualität.","legen",["legen","setzen","stellen"],"Klademe velký důraz na kvalitu."],["Er hat von seiner Familie Abschied ___ .","genommen",["genommen","gemacht","gegeben"],"Rozloučil se se svou rodinou."],["Der Vorschlag ___ auf breite Zustimmung.","stieß",["stieß","fand sich","kam"],"Návrh narazil na širokou podporu."],["Sie ___ ihm einen großen Gefallen.","tat",["tat","machte","gab"],"Udělala mu velkou laskavost."],["Das Thema ___ eine wichtige Rolle.","spielt",["spielt","macht","hat"],"To téma hraje důležitou roli."]]},
 {id:"de_c2_g_konnektoren",title:"Formální spojovací výrazy",type:'grammar',theory:"Vytříbený psaný projev používá formální konektory: <b>infolgedessen</b> (v důsledku toho), <b>gleichwohl</b> (nicméně), <b>demzufolge</b> (podle toho), <b>ungeachtet</b> (bez ohledu na), <b>insofern</b> (potud/pokud).",table:[["Konektor","Význam"],["infolgedessen","v důsledku toho"],["gleichwohl","nicméně"],["ungeachtet + Gen.","bez ohledu na"],["demzufolge","podle toho/tudíž"]],items:[["Es regnete stark; ___ wurde das Spiel abgesagt.","infolgedessen",["infolgedessen","gleichwohl","ungeachtet"],"Silně pršelo; v důsledku toho byl zápas zrušen."],["Der Plan war riskant; ___ stimmten alle zu.","gleichwohl",["gleichwohl","infolgedessen","demzufolge"],"Plán byl riskantní; nicméně všichni souhlasili."],["___ der Warnungen fuhr er weiter.","Ungeachtet",["Ungeachtet","Infolgedessen","Gleichwohl"],"Bez ohledu na varování jel dál."],["Die Nachfrage sank; ___ fielen die Preise.","demzufolge",["demzufolge","gleichwohl","ungeachtet"],"Poptávka klesla; tudíž klesly ceny."],["___ ich weiß, ist er verreist.","Soweit",["Soweit","Insofern als","Demzufolge"],"Pokud vím, je na cestách."],["Er hat recht, ___ es die Fakten betrifft.","insofern",["insofern","gleichwohl","infolge"],"Má pravdu, pokud jde o fakta."],["Das Projekt scheiterte; ___ war die Mühe nicht umsonst.","dennoch",["dennoch","demzufolge","infolgedessen"],"Projekt ztroskotal; přesto nebyla ta námaha zbytečná."],["___ dessen müssen wir neu planen.","Angesichts",["Angesichts","Gleichwohl","Dennoch"],"Vzhledem k tomu musíme plánovat znovu."]]},
 {id:"de_c2_g_ellipse",title:"Elipsa a zkrácené věty",type:'grammar',theory:"Pokročilá němčina vynechává opakující se části: Ich trinke Kaffee, er ___ Tee (vynecháno 'trinkt'). Wie besprochen… (jak bylo domluveno). Wenn nötig… (bude-li třeba). Falls möglich… (pokud možno).",table:[["Zkrácená forma","Plná forma"],["wie besprochen","wie es besprochen wurde"],["wenn nötig","wenn es nötig ist"],["falls möglich","falls es möglich ist"]],items:[["Wie ___ , schicke ich Ihnen die Unterlagen.","besprochen",["besprochen","bespricht","besprechen"],"Jak bylo domluveno, posílám vám podklady."],["Wenn ___ , rufen Sie mich an.","nötig",["nötig","nötige","nötigen"],"Bude-li třeba, zavolejte mi."],["Falls ___ , kommen Sie früher.","möglich",["möglich","mögliche","möglichen"],"Pokud možno, přijďte dřív."],["Ich nehme den Fisch, sie ___ Steak.","das",["das","isst das","nimmt"],"Já si dám rybu, ona steak."],["Wie ___ , beginnt das Meeting um neun.","vereinbart",["vereinbart","vereinbaren","vereinbarte"],"Jak bylo dohodnuto, schůzka začíná v devět."],["Er kommt heute, sie ___ .","morgen",["morgen","kommt sie","auch morgen kommt"],"On přijde dnes, ona zítra."],["Wenn auch spät, ___ er doch.","kam",["kam","kommt er","gekommen"],"I když pozdě, přece přišel."],["Je nach Wetter fahren wir ans Meer oder ___ die Berge.","in",["in","an","nach"],"Podle počasí pojedeme k moři, nebo do hor."]]},
 {id:"de_c2_g_stil",title:"Vytříbený styl a genitivní vazby",type:'grammar',theory:"Nejvyšší stylová úroveň: genitivní vazby (<b>angesichts</b>, <b>zwecks</b>, <b>mangels</b>, <b>kraft</b>, <b>anlässlich</b>) a knižní obraty: <b>seitens</b> der Regierung (ze strany vlády), <b>mittels</b> neuer Technologien (pomocí).",table:[["Předložka + Gen.","Význam"],["angesichts","vzhledem k"],["mangels","pro nedostatek"],["anlässlich","u příležitosti"],["seitens","ze strany"],["mittels","pomocí"]],items:[["___ der Krise wurden Reformen beschlossen.","Angesichts",["Angesichts","Mittels","Zwecks"],"Vzhledem ke krizi byly schváleny reformy."],["___ Beweisen wurde er freigesprochen.","Mangels",["Mangels","Anlässlich","Kraft"],"Pro nedostatek důkazů byl zproštěn viny."],["___ des Jubiläums gab es eine Feier.","Anlässlich",["Anlässlich","Mangels","Seitens"],"U příležitosti výročí se konala oslava."],["___ der Regierung gab es keine Stellungnahme.","Seitens",["Seitens","Mittels","Zwecks"],"Ze strany vlády nebylo žádné vyjádření."],["___ neuer Technologien wurde das Problem gelöst.","Mittels",["Mittels","Angesichts","Anlässlich"],"Pomocí nových technologií byl problém vyřešen."],["___ besserer Planung trafen wir uns früher.","Zwecks",["Zwecks","Mangels","Seitens"],"Za účelem lepšího plánování jsme se sešli dřív."],["___ seines Amtes traf er die Entscheidung.","Kraft",["Kraft","Mittels","Mangels"],"Z moci svého úřadu učinil rozhodnutí."],["___ des schlechten Wetters fiel das Fest aus.","Aufgrund",["Aufgrund","Zwecks","Kraft"],"Kvůli špatnému počasí se slavnost nekonala."]]}
